"use client";

import { useTeamTrophyShelf } from "./hooks/use-team-trophy-shelf";
import { TeamTrophyShelfEmpty } from "./parts/team-trophy-shelf-empty";
import { TeamTrophyShelfGrid } from "./parts/team-trophy-shelf-grid";
import { TeamTrophyShelfHeader } from "./parts/team-trophy-shelf-header";
import { TeamTrophyShelfRoot } from "./parts/team-trophy-shelf-root";
import type { TeamTrophyShelf01Props } from "./types";

/** Emptiness gate — routes to Grid or the designed Empty state. Reads context only. */
function TeamTrophyShelfBody() {
  const { slots } = useTeamTrophyShelf();
  return slots.length === 0 ? <TeamTrophyShelfEmpty /> : <TeamTrophyShelfGrid />;
}

/**
 * Tier A — the batteries-included assembly: `Root` + `showHeader`-gated `Header`
 * + (`Grid` | `Empty`). Contains **no logic the parts don't** — a hand-assembled
 * layout (`TeamTrophyShelfRoot` + a subset of parts) behaves identically.
 *
 * A durable gallery of ONE team's earned milestone badges, honest locked slots for
 * what's ahead, and a brief non-blocking reveal when a badge is newly earned. No
 * ranking, no per-member split, no comparison — ever (system §5.3 / D-08).
 */
export function TeamTrophyShelf01({
  badges,
  team,
  showLocked = true,
  showHeader = true,
  title,
  size = "md",
  animateAward = true,
  onEvent,
  onBadgeOpen,
  renderBadgeIcon,
  className,
  "aria-label": ariaLabel,
}: TeamTrophyShelf01Props) {
  return (
    <TeamTrophyShelfRoot
      badges={badges}
      team={team}
      showLocked={showLocked}
      title={title}
      size={size}
      animateAward={animateAward}
      onEvent={onEvent}
      onBadgeOpen={onBadgeOpen}
      renderBadgeIcon={renderBadgeIcon}
      className={className}
      aria-label={ariaLabel}
    >
      {showHeader ? <TeamTrophyShelfHeader /> : null}
      <TeamTrophyShelfBody />
    </TeamTrophyShelfRoot>
  );
}

// Tier A — batteries-included assembly.
export { TeamTrophyShelf01 } from "./team-trophy-shelf-01";

// Tier B — headless provider + flat à-la-carte parts.
export { TeamTrophyShelfRoot } from "./parts/team-trophy-shelf-root";
export { TeamTrophyShelfGrid } from "./parts/team-trophy-shelf-grid";
export { TeamTrophyShelfHeader } from "./parts/team-trophy-shelf-header";
export { TeamTrophyShelfEmpty } from "./parts/team-trophy-shelf-empty";

// Tier C — context-free primitives. The award overlay is the lazy-chunk host;
// the Grid pulls it via React.lazy, so importing it here for standalone use does
// not force it into a bare-token consumer's bundle (unused re-exports tree-shake).
export { TeamMilestoneBadge } from "./parts/team-milestone-badge";
export { default as BadgeAwardOverlay } from "./parts/badge-award-overlay";

// Context consumer for hand-assembled layouts.
export { useTeamTrophyShelf } from "./hooks/use-team-trophy-shelf";

// Public types.
export type {
  TeamTrophyShelf01Props,
  TeamTrophyShelfRootProps,
  TeamTrophyShelfBaseProps,
  TeamTrophyShelfContextValue,
  TeamMilestoneBadgeProps,
  BadgeAwardOverlayProps,
  Badge,
  Team,
  BadgeSize,
  GamificationEvent,
} from "./types";

import type { ReactNode } from "react";

/**
 * `team-trophy-shelf-01` — public type surface.
 *
 * Framework-free (no `"use client"`): importable from a server component's type
 * position. Per system D-03 every type is **re-declared locally** — this
 * component imports nothing from another registry component. The
 * `gamification-system` description (§4 domain model, §6 telemetry union) is the
 * source of truth these slices are copied from, not imported.
 */

/**
 * A team milestone trophy. `awardedAt` is the **single discriminator** of
 * earned vs locked: present → earned; absent → a not-yet-earned (locked) slot.
 */
export interface Badge {
  id: string;
  /** Badge label — e.g. "First playable build". Truncates; full label in tooltip. */
  label: string;
  /** ISO 8601 award time. `undefined` → NOT yet earned (locked slot). */
  awardedAt?: string;
  /** The milestone that earned it (shared spine, D-09). Optional link target. */
  milestoneId?: string;
}

/**
 * This team — identity subset (system D-15). `id` scopes telemetry; `name` is an
 * OPTIONAL header-title fallback (the name only feeds an optional title, so the
 * object stays `{ id; name? }`).
 */
export interface Team {
  id: string;
  name?: string;
}

/**
 * The system §6 union narrowed to this component's emit surface. `badgeId` is
 * present only on the per-badge "opened" event.
 */
export type GamificationEvent = {
  type: "badges.viewed";
  teamId: string;
  badgeId?: string;
};

export type BadgeSize = "sm" | "md";

/** Data + telemetry surface shared by the assembly and the headless `Root`. */
export interface TeamTrophyShelfBaseProps {
  /** This team's badges — earned AND (optionally) not-yet-earned slots. */
  badges: Badge[];
  /** The owning team (telemetry teamId + optional header-title fallback). D-15. */
  team: Team;
  /** Render not-yet-earned badges as locked slots. Default `true`. */
  showLocked?: boolean;
  /** Override the header title; defaults to `${team.name} trophies` / "Team trophies". */
  title?: string;
  /** Token size. Default `"md"`. */
  size?: BadgeSize;
  /**
   * Animate newly-earned badges (diff vs previous render). Default `true`.
   *
   * **D-16 (celebration ownership):** a host that routes badge/milestone events to
   * `team-feedback-loop-01` (E6) MUST set this `false` so the moment is not
   * celebrated twice. Neither component triggers the other; the host wires exactly
   * one path per event kind.
   */
  animateAward?: boolean;
  /** Telemetry — `badges.viewed` (system D-07 / §6). */
  onEvent?: (event: GamificationEvent) => void;
  /** Fired when a badge is opened/inspected; the consumer wires what opens. */
  onBadgeOpen?: (badge: Badge) => void;
  /** Custom badge artwork; falls back to a lucide glyph. */
  renderBadgeIcon?: (badge: Badge) => ReactNode;
  className?: string;
  "aria-label"?: string;
}

/** Props for the batteries-included `TeamTrophyShelf01` assembly. */
export interface TeamTrophyShelf01Props extends TeamTrophyShelfBaseProps {
  /** Render the header (title + earned count). Default `true`. */
  showHeader?: boolean;
}

/** Props for the headless provider `TeamTrophyShelfRoot`. */
export interface TeamTrophyShelfRootProps extends TeamTrophyShelfBaseProps {
  children: ReactNode;
}

/** Props for the context-free Tier-C `TeamMilestoneBadge` token. */
export interface TeamMilestoneBadgeProps {
  badge: Badge;
  size?: BadgeSize;
  /** Render the locked state when not earned. Default `true`. */
  showLocked?: boolean;
  onOpen?: (badge: Badge) => void;
  renderIcon?: (badge: Badge) => ReactNode;
  className?: string;
}

/** Props for the lazy Tier-C `BadgeAwardOverlay`. */
export interface BadgeAwardOverlayProps {
  /** The settling token to wrap. */
  children: ReactNode;
  /** Run the burst (the Grid passes true only for a newly-earned id). Default `false`. */
  active?: boolean;
  /** Called when the < 1s reveal completes (for chaining / cleanup). */
  onDone?: () => void;
  className?: string;
}

/** The resolved state every context part reads — one source of truth. */
export interface TeamTrophyShelfContextValue {
  /** Resolved list (earned + optional locked), in host order. */
  slots: Badge[];
  team: Team;
  title?: string;
  size: BadgeSize;
  showLocked: boolean;
  animateAward: boolean;
  /** IDs of badges earned since the previous render. */
  newAwards: ReadonlySet<string>;
  earnedCount: number;
  totalCount: number;
  /** True when `onBadgeOpen` was supplied — tokens become interactive buttons. */
  isInteractive: boolean;
  /** Open/inspect a badge (fires telemetry + `onBadgeOpen`). */
  openBadge: (badge: Badge) => void;
  /** Clear a badge from `newAwards` once its reveal completes. */
  onAwardDone: (badgeId: string) => void;
  renderBadgeIcon?: (badge: Badge) => ReactNode;
}

import type { Badge } from "../types";

/**
 * Earned-vs-locked resolution — pure, SSR-deterministic (derives only from
 * props; no `Date.now()`, no layout). `awardedAt` is the single discriminator.
 * Kit-extraction candidate (system §7.3) — keep standalone.
 */

export function isEarned(badge: Badge): boolean {
  return badge.awardedAt != null;
}

export function isLocked(badge: Badge): boolean {
  return badge.awardedAt == null;
}

/** Apply `showLocked`: drop not-yet-earned badges from the rendered list when false. */
export function resolveSlots(badges: Badge[], showLocked: boolean): Badge[] {
  return showLocked ? badges : badges.filter(isEarned);
}

export function earnedCount(badges: Badge[]): number {
  return badges.filter(isEarned).length;
}

export function totalCount(badges: Badge[]): number {
  return badges.length;
}

import { isEarned } from "./resolve";
import type { Badge } from "../types";

/**
 * The newly-earned diff — pure. Given the current badges and a map of the
 * previous render's badges by id, returns the set of ids whose `awardedAt` went
 * absent → present (i.e. just earned).
 *
 * SSR safety is achieved by the caller, not a `mounted` flag: the Root seeds its
 * "previous" from the FIRST render's badges (via `useState`), so on the initial
 * (and hydration) render `prev === current` for every id → the set is empty →
 * nothing animates on load. The reveal only appears after a subsequent controlled
 * `badges` update flips a badge's `awardedAt` on (exactly the host action D-d
 * describes). This avoids a `set-state-in-effect` mounted flag (which the repo's
 * lint rule forbids) while staying hydration-safe.
 */
export function newlyEarned(
  current: Badge[],
  prevById: Map<string, Badge>,
): Set<string> {
  const result = new Set<string>();
  for (const badge of current) {
    if (isEarned(badge) && prevById.get(badge.id)?.awardedAt == null) {
      result.add(badge.id);
    }
  }
  return result;
}

export function indexById(badges: Badge[]): Map<string, Badge> {
  return new Map(badges.map((badge) => [badge.id, badge]));
}

"use client";

import * as React from "react";

import type { TeamTrophyShelfContextValue } from "../types";

export const TeamTrophyShelfContext =
  React.createContext<TeamTrophyShelfContextValue | null>(null);

/**
 * Read the resolved shelf state from a surrounding `TeamTrophyShelfRoot`.
 * For hand-assembled layouts; throws if used outside a `Root`.
 */
export function useTeamTrophyShelf(): TeamTrophyShelfContextValue {
  const ctx = React.useContext(TeamTrophyShelfContext);
  if (ctx === null) {
    throw new Error(
      "useTeamTrophyShelf must be used within a <TeamTrophyShelfRoot>.",
    );
  }
  return ctx;
}

"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

import { TeamTrophyShelfContext } from "../hooks/use-team-trophy-shelf";
import { indexById, newlyEarned } from "../lib/diff";
import { earnedCount, resolveSlots, totalCount } from "../lib/resolve";
import type {
  Badge,
  TeamTrophyShelfContextValue,
  TeamTrophyShelfRootProps,
} from "../types";

const EMPTY_AWARDS: ReadonlySet<string> = new Set();

/**
 * Tier B — headless provider. Owns ALL state: the resolved slot list, the
 * **newly-earned diff** (SSR-safe), the `badges.viewed` telemetry, and the
 * open-badge callback path. Renders `children`. No layout opinion.
 *
 * The diff uses React's "storing information from previous renders" pattern
 * (setState **during render**, not in an effect): `prevBadges` is seeded from the
 * first render's `badges`, so the initial/hydration render sees `prev === current`
 * → no award animates on load. A later controlled `badges` update that flips a
 * badge's `awardedAt` on computes exactly one fresh award set. This avoids a
 * `set-state-in-effect` mounted flag (forbidden by the repo lint rule) and never
 * reads a ref during render.
 */
export function TeamTrophyShelfRoot({
  badges,
  team,
  showLocked = true,
  title,
  size = "md",
  animateAward = true,
  onEvent,
  onBadgeOpen,
  renderBadgeIcon,
  className,
  "aria-label": ariaLabel,
  children,
}: TeamTrophyShelfRootProps) {
  // --- SSR-safe newly-earned diff (setState during render) ---
  const [prevBadges, setPrevBadges] = React.useState<Badge[]>(badges);
  const [newAwards, setNewAwards] = React.useState<ReadonlySet<string>>(EMPTY_AWARDS);

  if (badges !== prevBadges) {
    setPrevBadges(badges);
    setNewAwards(
      animateAward ? newlyEarned(badges, indexById(prevBadges)) : EMPTY_AWARDS,
    );
  }

  // --- Derived (pure) ---
  const slots = React.useMemo(
    () => resolveSlots(badges, showLocked),
    [badges, showLocked],
  );
  const earned = React.useMemo(() => earnedCount(badges), [badges]);
  const total = React.useMemo(() => totalCount(badges), [badges]);

  // --- Telemetry: badges.viewed (no id) once on first view ---
  const firedView = React.useRef(false);
  const onEventRef = React.useRef(onEvent);
  React.useEffect(() => {
    onEventRef.current = onEvent;
  }, [onEvent]);
  const hasEventHandler = Boolean(onEvent);
  React.useEffect(() => {
    if (firedView.current || !hasEventHandler) return;
    firedView.current = true;
    onEventRef.current?.({ type: "badges.viewed", teamId: team.id });
  }, [team.id, hasEventHandler]);

  // --- Interaction ---
  const onBadgeOpenRef = React.useRef(onBadgeOpen);
  React.useEffect(() => {
    onBadgeOpenRef.current = onBadgeOpen;
  }, [onBadgeOpen]);
  const isInteractive = Boolean(onBadgeOpen);

  const openBadge = React.useCallback(
    (badge: Badge) => {
      onEventRef.current?.({
        type: "badges.viewed",
        teamId: team.id,
        badgeId: badge.id,
      });
      onBadgeOpenRef.current?.(badge);
    },
    [team.id],
  );

  const onAwardDone = React.useCallback((badgeId: string) => {
    setNewAwards((prev) => {
      if (!prev.has(badgeId)) return prev;
      const next = new Set(prev);
      next.delete(badgeId);
      return next;
    });
  }, []);

  const contextValue = React.useMemo<TeamTrophyShelfContextValue>(
    () => ({
      slots,
      team,
      title,
      size,
      showLocked,
      animateAward,
      newAwards,
      earnedCount: earned,
      totalCount: total,
      isInteractive,
      openBadge,
      onAwardDone,
      renderBadgeIcon,
    }),
    [
      slots,
      team,
      title,
      size,
      showLocked,
      animateAward,
      newAwards,
      earned,
      total,
      isInteractive,
      openBadge,
      onAwardDone,
      renderBadgeIcon,
    ],
  );

  return (
    <TeamTrophyShelfContext.Provider value={contextValue}>
      <section
        className={cn("flex w-full flex-col gap-3", className)}
        aria-label={ariaLabel ?? "Team trophies"}
      >
        {children}
      </section>
    </TeamTrophyShelfContext.Provider>
  );
}

"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

import { useTeamTrophyShelf } from "../hooks/use-team-trophy-shelf";
import { TeamMilestoneBadge } from "./team-milestone-badge";

// The ONLY reference to the overlay is this lazy import — its chunk loads solely
// when a newly-earned badge renders (never for the bare-token path or
// `animateAward={false}`). See the compound rule's lazy-boundary requirement.
const BadgeAwardOverlay = React.lazy(() => import("./badge-award-overlay"));

/**
 * Tier B — the responsive shelf grid (`role="list"`). Reads the resolved slots +
 * per-badge new-award flags from context, staggers a `reveal-up` entrance across
 * tokens, applies a cheap CSS "pop" to newly-earned tokens (works without the
 * lazy chunk), and wraps them in the lazy `BadgeAwardOverlay` for the richer burst.
 */
export function TeamTrophyShelfGrid({ className }: { className?: string }) {
  const {
    slots,
    size,
    showLocked,
    animateAward,
    newAwards,
    isInteractive,
    openBadge,
    onAwardDone,
    renderBadgeIcon,
  } = useTeamTrophyShelf();

  return (
    <ul role="list" className={cn("flex flex-wrap gap-4", className)}>
      {slots.map((badge, i) => {
        const isNew = animateAward && newAwards.has(badge.id);
        const token = (
          <TeamMilestoneBadge
            badge={badge}
            size={size}
            showLocked={showLocked}
            onOpen={isInteractive ? openBadge : undefined}
            renderIcon={renderBadgeIcon}
            className={
              isNew
                ? "motion-safe:animate-in motion-safe:zoom-in-50 motion-safe:duration-500"
                : undefined
            }
          />
        );

        return (
          <li
            key={badge.id}
            role="listitem"
            className="reveal-up"
            style={{ animationDelay: `${i * 60}ms` }}
          >
            {isNew ? (
              <React.Suspense fallback={token}>
                <BadgeAwardOverlay active onDone={() => onAwardDone(badge.id)}>
                  {token}
                </BadgeAwardOverlay>
              </React.Suspense>
            ) : (
              token
            )}
          </li>
        );
      })}
    </ul>
  );
}

"use client";

import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";

import { useTeamTrophyShelf } from "../hooks/use-team-trophy-shelf";

/**
 * Tier B — the optional header: the shelf title + an earned-count pill
 * ("4 / 9"). The count is "N of THIS team's M", never a rank or comparison.
 */
export function TeamTrophyShelfHeader({ className }: { className?: string }) {
  const { team, title, earnedCount, totalCount } = useTeamTrophyShelf();

  const heading =
    title ?? (team.name ? `${team.name} trophies` : "Team trophies");

  return (
    <div className={cn("flex items-center gap-3", className)}>
      <h3 className="text-sm font-semibold text-foreground">{heading}</h3>
      <Separator orientation="vertical" className="h-4" />
      <Badge variant="secondary" className="font-mono tabular-nums">
        {earnedCount} / {totalCount}
      </Badge>
    </div>
  );
}

"use client";

import { Trophy } from "lucide-react";

import { cn } from "@/lib/utils";

import { useTeamTrophyShelf } from "../hooks/use-team-trophy-shelf";

/**
 * Tier B — the designed empty state (no badges defined, or none earned with
 * `showLocked={false}`). Encouraging, Competence-positive — never an error or a
 * dead panel. Renders only when the resolved slot list is empty.
 */
export function TeamTrophyShelfEmpty({ className }: { className?: string }) {
  // Subscribe so the part throws if mis-mounted outside a Root (consistency).
  useTeamTrophyShelf();

  return (
    <div
      className={cn(
        "flex flex-col items-center gap-2 rounded-xl border border-dashed border-border bg-muted/30 px-6 py-10 text-center",
        className,
      )}
    >
      <Trophy className="size-8 text-muted-foreground/60" aria-hidden />
      <p className="text-sm font-medium text-foreground">No trophies yet</p>
      <p className="max-w-xs text-xs text-muted-foreground">
        Milestones your team completes will land here.
      </p>
    </div>
  );
}

"use client";

import * as React from "react";
import { Lock, Trophy } from "lucide-react";

import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";

import { isEarned } from "../lib/resolve";
import type { TeamMilestoneBadgeProps } from "../types";

const MONTHS = [
  "Jan", "Feb", "Mar", "Apr", "May", "Jun",
  "Jul", "Aug", "Sep", "Oct", "Nov", "Dec",
];

/**
 * Deterministic, locale/TZ-independent date format (UTC parts + fixed month
 * names) so the awarded-date reads identically on server + client — no hydration
 * mismatch. Returns null for an unparseable `awardedAt`.
 */
function formatAwardedDate(iso: string): string | null {
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return null;
  return `${d.getUTCDate()} ${MONTHS[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
}

/**
 * Tier C — the load-bearing standalone token. Earned (lime medallion + glyph +
 * awarded-date tooltip) vs locked (desaturated, dashed, `Lock` glyph). Usable
 * anywhere with zero shelf scaffolding. Interactive only when `onOpen` is passed
 * (a real `<button>`); otherwise a non-focusable `role="img"` (no dead affordances).
 * State is conveyed by glyph + text, never color alone.
 */
export function TeamMilestoneBadge({
  badge,
  size = "md",
  showLocked = true,
  onOpen,
  renderIcon,
  className,
}: TeamMilestoneBadgeProps) {
  const earned = isEarned(badge);
  if (!earned && !showLocked) return null;

  const awardedText =
    earned && badge.awardedAt ? formatAwardedDate(badge.awardedAt) : null;
  const ariaLabel = earned
    ? `${badge.label} — earned${awardedText ? ` ${awardedText}` : ""}`
    : `${badge.label} — locked`;

  const interactive = typeof onOpen === "function";
  const medallionSize = size === "sm" ? "size-10" : "size-16";
  const glyphSize = size === "sm" ? "size-4" : "size-6";

  const icon = renderIcon ? (
    renderIcon(badge)
  ) : earned ? (
    <Trophy className={glyphSize} aria-hidden />
  ) : (
    <Lock className={glyphSize} aria-hidden />
  );

  const inner = (
    <>
      <span
        className={cn(
          "flex items-center justify-center rounded-2xl transition-colors",
          medallionSize,
          earned
            ? "bg-primary text-primary-foreground shadow-sm"
            : "border border-dashed border-border bg-muted text-muted-foreground",
        )}
      >
        {icon}
      </span>
      <span
        className={cn(
          "max-w-32 truncate text-center text-xs",
          size === "sm" && "max-w-24",
          earned ? "text-foreground" : "text-muted-foreground",
        )}
      >
        {badge.label}
      </span>
    </>
  );

  const wrapperCls = cn(
    "inline-flex flex-col items-center gap-1.5 rounded-2xl outline-none",
    interactive &&
      "cursor-pointer focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background",
    className,
  );

  const token = interactive ? (
    <button
      type="button"
      onClick={() => onOpen?.(badge)}
      aria-label={ariaLabel}
      className={wrapperCls}
    >
      {inner}
    </button>
  ) : (
    <span role="img" aria-label={ariaLabel} title={badge.label} className={wrapperCls}>
      {inner}
    </span>
  );

  // Awarded-date tooltip only for earned badges (client-only render → SSR-safe).
  if (earned && awardedText) {
    return (
      <TooltipProvider>
        <Tooltip>
          <TooltipTrigger asChild>{token}</TooltipTrigger>
          <TooltipContent>Earned {awardedText}</TooltipContent>
        </Tooltip>
      </TooltipProvider>
    );
  }

  return token;
}

"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

import type { BadgeAwardOverlayProps } from "../types";

/**
 * Tier C (lazy) — the brief (< 1s), non-blocking award reveal. Wraps the settling
 * token and layers a hand-rolled spark burst over it (zero npm animation dep —
 * built from Tailwind's `animate-ping`). The burst is `aria-hidden`, never traps
 * or steals focus, never blocks input/scroll (D-10), and is `motion-reduce:hidden`
 * so `prefers-reduced-motion` skips straight to the settled token.
 *
 * DEFAULT export so the Grid can pull it via `React.lazy(() => import(...))` — this
 * is the ONLY weight-bearing module; the bare-token path and `animateAward={false}`
 * never load its chunk.
 */
export default function BadgeAwardOverlay({
  children,
  active = false,
  onDone,
  className,
}: BadgeAwardOverlayProps) {
  const onDoneRef = React.useRef(onDone);
  React.useEffect(() => {
    onDoneRef.current = onDone;
  }, [onDone]);

  React.useEffect(() => {
    if (!active) return;
    const timer = setTimeout(() => onDoneRef.current?.(), 900);
    return () => clearTimeout(timer);
  }, [active]);

  return (
    <span className={cn("relative inline-flex", className)}>
      {children}
      {active ? (
        <span
          aria-hidden
          className="pointer-events-none absolute inset-0 z-10 motion-reduce:hidden"
        >
          <span className="absolute left-1/2 top-1/2 size-14 -translate-x-1/2 -translate-y-1/2 rounded-full bg-primary/25 animate-ping" />
          {SPARKS.map((spark, i) => (
            <span
              key={i}
              className="absolute left-1/2 top-1/2 size-1.5 rounded-full bg-primary animate-ping"
              style={{
                transform: `translate(-50%, -50%) translate(${spark.x}px, ${spark.y}px)`,
                animationDelay: `${spark.delay}ms`,
                animationDuration: "700ms",
              }}
            />
          ))}
        </span>
      ) : null}
    </span>
  );
}

// Fixed spark offsets (no Math.random → deterministic, SSR-safe).
const SPARKS = [
  { x: 0, y: -26, delay: 0 },
  { x: 22, y: -14, delay: 60 },
  { x: 26, y: 8, delay: 120 },
  { x: 14, y: 24, delay: 60 },
  { x: -14, y: 24, delay: 120 },
  { x: -26, y: 8, delay: 0 },
  { x: -22, y: -14, delay: 60 },
];
